export function expandEmbedded(raw) {
  const out = {};
  for (const [tk, bars] of Object.entries(raw)) {
    out[tk] = bars.map(b => ({
      date:b.d, hour:b.h, open:b.o, high:b.hi,
      low:b.lo, close:b.c, volume:b.v, moneda:b.m, _ticker:tk
    }));
  }
  return out;
}

